export enum Category {
  MANIFESTO = 'manifesto',
  MEDIA = 'media',
  BOOKS = 'books',
  RESEARCH = 'research',
  CULTURE = 'culture',
  COUNTRIES = 'countries',
  CONTEXT_ENGINE = 'context_engine'
}

export interface ResourceItem {
  id: string;
  title: string;
  authorOrSource: string;
  description: string;
  type: 'article' | 'book' | 'data' | 'video' | 'audio' | 'profile';
  tags: string[];
  imageUrl?: string;
  link?: string;
}

export interface CountryProfile {
