import React, { useState, useRef, useEffect } from 'react';
import { Sparkles, Send, Bot, User, Info } from 'lucide-react';
import { generateContextResponse } from '../services/geminiService';
import { ChatMessage } from '../types';

const ContextEngine: React.FC = () => {
  const [query, setQuery] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'I am the Context Engine. I can help provide historical background, economic context, or regional nuance on African topics. What would you like to understand better?'
    }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim() || isLoading) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: query };
    setMessages(prev => [...prev, userMsg]);
    setQuery('');
    setIsLoading(true);

    try {
      const responseText = await generateContextResponse(userMsg.text);
      const aiMsg: ChatMessage = { 
        id: (Date.now() + 1).toString(), 
        role: 'model', 
        text: responseText 
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      // Error handled in service, but safety fallback
      setMessages(prev => [...prev, { id: 'err', role: 'model', text: 'Something went wrong. Please try again.' }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto h-[calc(100vh-4rem)] md:h-screen flex flex-col bg-white md:border-x border-stone-200">

      {/* Header */}
      <div className="p-6 border-b border-stone-100 bg-white/80 backdrop-blur sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-earth-sage/20 rounded-lg text-earth-sage">
            <Sparkles size={24} />
          </div>
          <div>
            <h2 className="font-serif text-xl text-stone-900">Context Engine</h2>
            <p className="text-xs text-stone-500">Powered by Gemini • Designed for nuance</p>
          </div>
        </div>
      </div>

      {/* Chat Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-8" ref={scrollRef}>
        {messages.map((msg) => (
          <div key={msg.id} className={`flex gap-4 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            {msg.role === 'model' && (
              <div className="w-8 h-8 rounded-full bg-stone-100 flex items-center justify-center shrink-0">
                <Bot size={16} className="text-stone-500" />
              </div>
            )}

            <div className={`max-w-[80%] space-y-1 ${msg.role === 'user' ? 'items-end flex flex-col' : ''}`}>
              <div 
                className={`
                  p-5 rounded-2xl text-sm leading-relaxed
                  ${msg.role === 'user' 
                    ? 'bg-stone-900 text-stone-50 rounded-tr-sm' 
                    : 'bg-stone-50 text-stone-800 border border-stone-100 rounded-tl-sm'}
                `}
              >
                 {msg.text.split('\n').map((line, i) => (
                    <p key={i} className={i > 0 ? 'mt-3' : ''}>{line}</p>
                 ))}
              </div>
              <span className="text-[10px] text-stone-400 px-1">
                {msg.role === 'user' ? 'You' : 'Context Engine'}
              </span>
            </div>

            {msg.role === 'user' && (
              <div className="w-8 h-8 rounded-full bg-earth-clay flex items-center justify-center shrink-0 text-white">
                <User size={16} />
              </div>
            )}
          </div>
        ))}

        {isLoading && (
          <div className="flex gap-4">
             <div className="w-8 h-8 rounded-full bg-stone-100 flex items-center justify-center shrink-0">
                <Bot size={16} className="text-stone-500" />
              </div>
              <div className="bg-stone-50 border border-stone-100 p-5 rounded-2xl rounded-tl-sm w-32 flex items-center gap-1">
                <div className="w-2 h-2 bg-stone-400 rounded-full animate-bounce delay-0"></div>
                <div className="w-2 h-2 bg-stone-400 rounded-full animate-bounce delay-150"></div>
                <div className="w-2 h-2 bg-stone-400 rounded-full animate-bounce delay-300"></div>
              </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-6 bg-white border-t border-stone-100">
        <form onSubmit={handleSearch} className="relative">
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Ask for context (e.g., 'What is the history of trade unions in South Africa?')"
            className="w-full bg-stone-50 border border-stone-200 rounded-xl py-4 pl-5 pr-14 text-sm focus:outline-none focus:ring-2 focus:ring-stone-200 transition-all placeholder:text-stone-400"
          />
          <button 
            type="submit"
            disabled={!query.trim() || isLoading}
            className="absolute right-2 top-2 p-2 bg-stone-900 text-white rounded-lg hover:bg-stone-800 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send size={18} />
          </button>
        </form>
        <div className="mt-3 flex gap-2 items-center justify-center text-[10px] text-stone-400">
            <Info size={12} />
            <span>AI can make mistakes. Always verify with primary sources.</span>
        </div>
      </div>
    </div>
  );
};

export default ContextEngine;

