                  <p className="text-xs text-stone-400 mb-4 uppercase tracking-wider">Distinguish between:</p>
                  <ul className="space-y-3">
                    {selectedCountry.specificity.map((note, idx) => (
                      <li key={idx} className="text-sm border-l border-stone-700 pl-3 leading-snug text-stone-200">
