        <p className="text-stone-500 dark:text-stone-400 text-lg max-w-2xl">
          Specific entry points to combat the "Africa is a country" narrative. 
          Select a country to dive deeper.
        </p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {countries.map((country) => (
          <button 
            key={country.id} 
            onClick={() => setSelectedCountryId(country.id)}
            className="text-left bg-white dark:bg-stone-900 border border-stone-200 dark:border-stone-800 rounded-xl p-8 hover:shadow-xl hover:border-stone-300 dark:hover:border-stone-700 hover:-translate-y-1 transition-all duration-300 group h-full flex flex-col"
          >
            <div className="flex justify-between items-start mb-6 w-full">
