import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import Layout from './components/Layout';
import HomePage from './pages/HomePage';
import GuidePage from './pages/GuidePage';
import CategoryPage from './pages/CategoryPage';
import SearchPage from './pages/SearchPage';
import { DataProvider } from './context/DataContext';

const ScrollToTop = () => {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);
  return null;
};

const App: React.FC = () => {
  const [isDark, setIsDark] = useState(false);

  useEffect(() => {
    const checkTheme = () => {
      const hour = new Date().getHours();
      const shouldBeDark = hour >= 19 || hour < 7;

      const storedTheme = localStorage.getItem('theme');
      if (storedTheme) {
        setIsDark(storedTheme === 'dark');
      } else {
        setIsDark(shouldBeDark);
      }
    };

    checkTheme();
    const interval = setInterval(checkTheme, 1000 * 60 * 30); // Check every 30 mins
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDark]);

  const toggleTheme = () => {
    const next = !isDark;
    setIsDark(next);
    localStorage.setItem('theme', next ? 'dark' : 'light');
  };

  return (
    <DataProvider>
      <Router>
        <ScrollToTop />
        <Layout isDark={isDark} onToggleTheme={toggleTheme}>
          <Routes>
            <Route path="/" element={<HomePage />} />
            <Route path="/guide/:id" element={<GuidePage />} />
            <Route path="/category/:id" element={<CategoryPage />} />
            <Route path="/search" element={<SearchPage />} />
            <Route path="/about" element={
              <div className="max-w-2xl mx-auto px-6 py-24">
                <h1 className="text-4xl font-bold mb-8">About Signpost</h1>
                <p className="text-xl text-brand-zinc-500 leading-relaxed mb-6">
                  Signpost is a citizen-driven initiative designed to demystify public services in Nigeria. 
                  Our mission is to provide accurate, up-to-date, and easy-to-understand guides for everyday processes.
                </p>
                <p className="text-brand-zinc-500 leading-relaxed">
                  We believe that information is a public right. By organizing the chaos of public bureaucracy, 
                  we empower millions of Nigerians to save time and avoid extortion.
                </p>
              </div>
            } />
          </Routes>
        </Layout>
      </Router>
    </DataProvider>
  );
};

export default App;

